# multi_slo_gate.py — check all SLO budgets before deploy
from typing import list

def deploy_gate(slo_statuses: list[ErrorBudgetStatus]) -> tuple[bool, str]:
    """
    Returns (allowed, reason).
    Blocked if ANY SLO budget is below the freeze threshold.
    """
    for status in slo_statuses:
        if not status.deploy_allowed:
            return False, (
                f"Deploy blocked by {status.policy_level} policy: "
                f"budget at {status.budget_pct:.1f}%"
            )
    lowest = min(slo_statuses, key=lambda s: s.budget_pct)
    if lowest.policy_level == "elevated_caution":
        return True, (
            f"Deploy allowed with elevated caution: "
            f"lowest budget is {lowest.budget_pct:.1f}%. "
            f"SRE review required before deploy."
        )
    return True, f"Deploy allowed: lowest budget is {lowest.budget_pct:.1f}%"
